import{_ as a,o,c as t,a0 as r}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"ADR-0004: AgentGateway como Proxy LLM para Failover Multi-Provider","description":"","frontmatter":{},"headers":[],"relativePath":"20_Arquitetura/adr/0004-agentgateway-gateway.md","filePath":"20_Arquitetura/adr/0004-agentgateway-gateway.md","lastUpdated":1783623176000}'),i={name:"20_Arquitetura/adr/0004-agentgateway-gateway.md"};function n(s,e,l,d,c,u){return o(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="adr-0004-agentgateway-como-proxy-llm-para-failover-multi-provider" tabindex="-1">ADR-0004: AgentGateway como Proxy LLM para Failover Multi-Provider <a class="header-anchor" href="#adr-0004-agentgateway-como-proxy-llm-para-failover-multi-provider" aria-label="Permalink to &quot;ADR-0004: AgentGateway como Proxy LLM para Failover Multi-Provider&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Aceito (Active)</p><h2 id="contexto" tabindex="-1">Contexto <a class="header-anchor" href="#contexto" aria-label="Permalink to &quot;Contexto&quot;">​</a></h2><p>O NEXUS utiliza o OpenRouter como provider primário de LLM através do modelo gratuito <code>deepseek/deepseek-v4-flash:free</code>. Este modelo free tier está sujeito a erros de rate limiting (HTTP 429) e indisponibilidade temporária (HTTP 503) sob carga, impactando a produtividade do desenvolvimento com interrupções frequentes (&quot;Model busy&quot;).</p><p>O stack NEXUS já inclui um Ollama local (<code>qwen2.5-coder:nexus</code>) como fallback offline de última instância, mas o Ollama não é um substituto adequado para tarefas que exigem capacidade de raciocínio superior — seu modelo 1.5B tem performance significativamente inferior ao DeepSeek V4 Flash.</p><p>Alternativas disponíveis:</p><ul><li><strong>DeepSeek Direct (API paga)</strong>: Oferece <code>deepseek-chat</code> com disponibilidade superior, mas não possui mecanismo nativo de failover.</li><li><strong>OpenCode fallbacks</strong>: O OpenCode suporta configuração de modelos fallback, mas a transição entre eles não é transparente para o usuário.</li></ul><p>Necessitamos de uma solução que:</p><ol><li>Faça failover automático e transparente entre providers</li><li>Evite requests síncronas para provedores indisponíveis com eviction por saúde</li><li>Ofereça load balancing entre provedores configuráveis</li><li>Exponha uma API compatível com OpenAI para integração mínima</li><li>Seja leve em recursos (mínimo overhead de latência e memória)</li><li>Funcione em modo standalone sem dependência de Kubernetes</li></ol><h2 id="correcao-retrospective" tabindex="-1">Correção / Retrospective <a class="header-anchor" href="#correcao-retrospective" aria-label="Permalink to &quot;Correção / Retrospective&quot;">​</a></h2><p>A arquitetura de failover original proposta nesta ADR (ADR-0004) foi revisada e encontrada incorreta. O modo standalone do AgentGateway <strong>não suporta failover baseado em prioridade entre providers</strong>. Os modelos são roteados apenas por <code>name</code>, sem mecanismos automáticos de eviction ou fallback. O catch-all <code>*</code> apenas roteia todas as requisições para o OpenRouter.</p><p>A solução real para a rotação de chaves é o <strong>KeyRotator</strong>, um sidecar Python.</p><h3 id="atualizacao-feature-50" tabindex="-1">Atualização (Feature 50) <a class="header-anchor" href="#atualizacao-feature-50" aria-label="Permalink to &quot;Atualização (Feature 50)&quot;">​</a></h3><p>Em Junho de 2026, o <code>key-rotator</code> foi reativado e reconfigurado no <code>compose.yaml</code> para atuar como o proxy de rodízio de chaves da API do Gemini (<code>GEMINI_API_KEYS</code>). O <code>AgentGateway</code> foi configurado para direcionar requisições <code>*</code> ao <code>key-rotator</code> local na porta 8090.</p><h2 id="decisao" tabindex="-1">Decisão <a class="header-anchor" href="#decisao" aria-label="Permalink to &quot;Decisão&quot;">​</a></h2><p>Integrar <strong>AgentGateway</strong> como proxy LLM no stack NEXUS, cooperando com o <strong>KeyRotator</strong> que gerencia a rotação de chaves e o tratamento de rate limits (429) da API do Gemini.</p><h3 id="arquitetura" tabindex="-1">Arquitetura <a class="header-anchor" href="#arquitetura" aria-label="Permalink to &quot;Arquitetura&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OpenCode/Claude → KeyRotator :8090/v1 (API compatível com OpenAI)</span></span>
<span class="line"><span>  → OpenRouter (N API keys, round-robin, 429 detection, per-key cooldown)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AgentGateway :8080/v1 (infra auxiliar)</span></span></code></pre></div><h3 id="keyrotator-solucao-de-rotacao-de-chaves" tabindex="-1">KeyRotator (Solução de Rotação de Chaves) <a class="header-anchor" href="#keyrotator-solucao-de-rotacao-de-chaves" aria-label="Permalink to &quot;KeyRotator (Solução de Rotação de Chaves)&quot;">​</a></h3><p>O KeyRotator é um sidecar Python (<code>docker/agentgateway/key-rotator/proxy.py</code>) que implementa a rotação de chaves para o OpenRouter.</p><ul><li><strong>Mecanismo</strong>: N API keys configuradas via <code>OPENROUTER_API_KEYS</code> (lista separada por vírgulas).</li><li><strong>Seleção</strong>: Round-robin entre as chaves ativas.</li><li><strong>Tratamento de 429</strong>: Detecta respostas HTTP 429 (Too Many Requests) e coloca a chave em cooldown por um período (<code>KEY_BACKOFF_SECONDS</code>, padrão 30s).</li><li><strong>Resiliência</strong>: Garante que requests não sejam enviados para chaves em cooldown, aumentando a resiliência contra rate limiting.</li></ul><h3 id="configuracao" tabindex="-1">Configuração <a class="header-anchor" href="#configuracao" aria-label="Permalink to &quot;Configuração&quot;">​</a></h3><ul><li><strong>Config file</strong>: <code>docker/agentgateway/config.yaml</code> montado como volume read-only em <code>/etc/agentgateway/config.yaml</code></li><li><strong>API keys</strong>: Injetadas via variáveis de ambiente (<code>$OPENROUTER_API_KEY</code>, <code>$DEEPSEEK_API_KEY</code>), definidas no <code>.env</code></li><li><strong>Porta</strong>: 8080 (mapeada para o host)</li><li><strong>Logging</strong>: JSON estruturado para observabilidade</li><li><strong>Métricas</strong>: Endpoint Prometheus em <code>localhost:15020</code></li></ul><h3 id="fluxo-de-rotacao-de-chaves-keyrotator" tabindex="-1">Fluxo de Rotação de Chaves (KeyRotator) <a class="header-anchor" href="#fluxo-de-rotacao-de-chaves-keyrotator" aria-label="Permalink to &quot;Fluxo de Rotação de Chaves (KeyRotator)&quot;">​</a></h3><ol><li>Request chega → KeyRotator seleciona uma chave OpenRouter ativa (round-robin).</li><li>Request é enviado ao OpenRouter com a chave selecionada.</li><li>Se OpenRouter responde 429 (rate limit) → a chave é colocada em cooldown por <code>KEY_BACKOFF_SECONDS</code> (padrão 30s).</li><li>Próximos requests → KeyRotator seleciona a próxima chave disponível no pool.</li><li>Chaves em cooldown são reativadas após o período, retornando ao pool ativo.</li></ol><h2 id="alternativas-consideradas" tabindex="-1">Alternativas Consideradas <a class="header-anchor" href="#alternativas-consideradas" aria-label="Permalink to &quot;Alternativas Consideradas&quot;">​</a></h2><h3 id="portkey-saas" tabindex="-1">Portkey (SaaS) <a class="header-anchor" href="#portkey-saas" aria-label="Permalink to &quot;Portkey (SaaS)&quot;">​</a></h3><ul><li><strong>Prós</strong>: Gerenciado, UI de monitoramento, cache de respostas</li><li><strong>Contras</strong>: Custo mensal recorrente, dependência de serviço externo, latência adicional de rede, dados passam por terceiros</li><li><strong>Veredito</strong>: Rejeitado — custo e dependência externa desnecessários</li></ul><h3 id="litellm-proxy-python" tabindex="-1">LiteLLM (Proxy Python) <a class="header-anchor" href="#litellm-proxy-python" aria-label="Permalink to &quot;LiteLLM (Proxy Python)&quot;">​</a></h3><ul><li><strong>Prós</strong>: Open source, suporte a 100+ providers, failover nativo</li><li><strong>Contras</strong>: Baseado em Python (mais pesado que Rust), maior consumo de recursos, dependência de pip/requirements, latency overhead maior</li><li><strong>Veredito</strong>: Rejeitado — mais pesado que o necessário para nosso caso de uso</li></ul><h3 id="custom-proxy-implementacao-propria" tabindex="-1">Custom Proxy (implementação própria) <a class="header-anchor" href="#custom-proxy-implementacao-propria" aria-label="Permalink to &quot;Custom Proxy (implementação própria)&quot;">​</a></h3><ul><li><strong>Prós</strong>: Controle total, sem dependências externas</li><li><strong>Contras</strong>: Custo de manutenção elevado, desenvolvimento do zero, validação de comportamento de failover complexa</li><li><strong>Veredito</strong>: Rejeitado — não justifica o custo de desenvolvimento</li></ul><h3 id="agentgateway-—-infraestrutura-auxiliar" tabindex="-1">AgentGateway — Infraestrutura Auxiliar <a class="header-anchor" href="#agentgateway-—-infraestrutura-auxiliar" aria-label="Permalink to &quot;AgentGateway — Infraestrutura Auxiliar&quot;">​</a></h3><blockquote><p><strong>Nota</strong>: O AgentGateway foi escolhido como proxy de infraestrutura, mas <strong>não para failover multi-provider</strong>. Ver &quot;Correção / Retrospective&quot; acima.</p></blockquote><ul><li><strong>Prós</strong>: <ul><li>Desenvolvido em Rust (performance nativa, ~1-5ms de overhead)</li><li>Mantido pela Linux Foundation (governança neutra)</li><li>Modo standalone sem K8s (binário único + YAML)</li><li>CORS, rate limiting e logging JSON built-in</li><li>Hot-reload de configuração</li><li>Cerca de 50MB de RAM</li></ul></li><li><strong>Contras</strong>: <ul><li>Modo standalone <strong>não</strong> suporta failover automático entre providers</li><li>Documentação focada em K8s (modo standalone menos documentado)</li><li>Ecossistema em maturação (v1.3.x)</li><li>Dependência de container registry externo</li></ul></li><li><strong>Veredito</strong>: Escolhido como infraestrutura auxiliar. KeyRotator provê a funcionalidade de rotação de chaves que realmente resolve o problema.</li></ul><h2 id="consequencias" tabindex="-1">Consequências <a class="header-anchor" href="#consequencias" aria-label="Permalink to &quot;Consequências&quot;">​</a></h2><h3 id="positivas" tabindex="-1">Positivas <a class="header-anchor" href="#positivas" aria-label="Permalink to &quot;Positivas&quot;">​</a></h3><ul><li>KeyRotator faz rotação automática de chaves com cooldown em 429</li><li>Transparência para OpenCode — mesma API compatível com OpenAI</li><li>API keys centralizadas em um único local (<code>.env</code>)</li><li>Logging JSON facilita monitoramento e debugging</li><li>KeyRotator ~50 linhas Python (zero dependências externas, stdlib only)</li></ul><h3 id="negativas" tabindex="-1">Negativas <a class="header-anchor" href="#negativas" aria-label="Permalink to &quot;Negativas&quot;">​</a></h3><ul><li>Dois containers adicionais no stack (KeyRotator + AgentGateway)</li><li>KeyRotator não suporta streaming SSE (request/response síncrono)</li><li>Latência adicional (~1-5ms por request no KeyRotator)</li></ul><h3 id="neutras" tabindex="-1">Neutras <a class="header-anchor" href="#neutras" aria-label="Permalink to &quot;Neutras&quot;">​</a></h3><ul><li>KeyRotator usa stdlib Python (sem dependências pip)</li><li>API keys gerenciadas via variáveis de ambiente (seguindo padrão existente)</li><li>Ambos os serviços são aditivos — remoção não quebra o stack</li></ul><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><ol><li>✅ KeyRotator implementado e configurado no compose.yaml</li><li>✅ OpenCode configurado para rotear via KeyRotator (documentado)</li><li>✅ Feature 50 (Unified Router) arquivada — manter AgentGateway + KeyRotator como estão</li><li>Pendente: Ajustar parâmetros de cooldown conforme observação empírica</li><li>Pendente: Testar com 3+ chaves em paralelo para validar resiliência</li></ol>`,45)])])}const h=a(i,[["render",n]]);export{m as __pageData,h as default};
